"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["25668"],{62987(e){e.exports=JSON.parse('{"tag":{"label":"events","permalink":"/sysanalyst-kb.github.io/docs/tags/events","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":6,"items":[{"id":"modeling/bpmn-advanced","title":"BPMN \u2014 \u043F\u0440\u043E\u0434\u0432\u0438\u043D\u0443\u0442\u044B\u0439 \u0443\u0440\u043E\u0432\u0435\u043D\u044C","description":"\u0411\u0430\u0437\u043E\u0432\u044B\u0439 BPMN \u043F\u043E\u043A\u0440\u044B\u0432\u0430\u0435\u0442 80%\u65E5\u5E38\u043D\u044B\u0445 \u0437\u0430\u0434\u0430\u0447 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430. \u041E\u0441\u0442\u0430\u0432\u0448\u0438\u0435\u0441\u044F 20% \u2014 \u043F\u043E\u0434\u043F\u0440\u043E\u0446\u0435\u0441\u0441\u044B, \u0441\u043E\u0431\u044B\u0442\u0438\u044F-\u0442\u0430\u0439\u043C\u0435\u0440\u044B, \u0438\u0441\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u044F \u0438 \u0442\u0440\u0430\u043D\u0437\u0430\u043A\u0446\u0438\u0438 \u2014 \u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u044E\u0442 \u0441\u0445\u0435\u043C\u0443 \u0438\u0437 \u043D\u0430\u0433\u043B\u044F\u0434\u043D\u043E\u0439 \u043A\u0430\u0440\u0442\u0438\u043D\u043A\u0438 \u0432 \u0444\u043E\u0440\u043C\u0430\u043B\u044C\u043D\u0443\u044E \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044E, \u043F\u043E \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u043C\u043E\u0436\u043D\u043E \u0440\u0435\u0430\u043B\u0438\u0437\u043E\u0432\u0430\u0442\u044C \u043F\u0440\u043E\u0446\u0435\u0441\u0441.","permalink":"/sysanalyst-kb.github.io/docs/modeling/bpmn-advanced"},{"id":"integration/event-driven-architecture","title":"Event-Driven Architecture (\u0432\u0432\u0435\u0434\u0435\u043D\u0438\u0435)","description":"Event-Driven Architecture (EDA) \u2014 \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u043D\u044B\u0439 \u0441\u0442\u0438\u043B\u044C, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442\u044B \u043E\u0431\u0449\u0430\u044E\u0442\u0441\u044F \u0447\u0435\u0440\u0435\u0437 \u0441\u043E\u0431\u044B\u0442\u0438\u044F, \u0430 \u043D\u0435 \u0447\u0435\u0440\u0435\u0437 \u043F\u0440\u044F\u043C\u044B\u0435 \u0432\u044B\u0437\u043E\u0432\u044B. \u0415\u0441\u043B\u0438 \u043C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u044B \u2014 \u043F\u0440\u043E \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u044C \u0434\u0435\u043F\u043B\u043E\u044F, \u0442\u043E EDA \u2014 \u043F\u0440\u043E \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u044C \u0432\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0438 \u0438 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435.","permalink":"/sysanalyst-kb.github.io/docs/integration/event-driven-architecture"},{"id":"architecture/eda-detailed","title":"Event-Driven Architecture (\u0434\u0435\u0442\u0430\u043B\u044C\u043D\u043E)","description":"\u0412\u044B \u0443\u0436\u0435 \u0437\u043D\u0430\u0435\u0442\u0435 \u043E\u0441\u043D\u043E\u0432\u044B EDA \u0438\u0437 \u0440\u0430\u0437\u0434\u0435\u043B\u0430 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438. \u0422\u0435\u043F\u0435\u0440\u044C \u0440\u0430\u0441\u0441\u043C\u043E\u0442\u0440\u0438\u043C \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u043D\u044B\u0435 \u0430\u0441\u043F\u0435\u043A\u0442\u044B: \u043A\u0430\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0441\u043E\u0431\u044B\u0442\u0438\u044F, \u043A\u0430\u043A \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u043E\u0432\u044B\u0432\u0430\u0442\u044C \u043F\u043E\u0442\u043E\u043A\u0438 \u0438 \u043A\u0430\u043A EDA \u043C\u0435\u043D\u044F\u0435\u0442 \u0434\u0438\u0437\u0430\u0439\u043D \u0441\u0438\u0441\u0442\u0435\u043C\u044B.","permalink":"/sysanalyst-kb.github.io/docs/architecture/eda-detailed"},{"id":"specialization/gamedev-analytics","title":"Game Analytics","description":"Game Analytics \u2014 \u0444\u0443\u043D\u0434\u0430\u043C\u0435\u043D\u0442 \u0432\u0441\u0435\u0445 \u0440\u0435\u0448\u0435\u043D\u0438\u0439 \u0432 \u0438\u0433\u0440\u0430\u0445. \u0422\u0440\u0435\u043A\u0438\u043D\u0433 \u0441\u043E\u0431\u044B\u0442\u0438\u0439 (event tracking), \u043F\u043E\u0441\u0442\u0440\u043E\u0435\u043D\u0438\u0435 \u0432\u043E\u0440\u043E\u043D\u043E\u043A (funnel), \u0430\u043D\u0430\u043B\u0438\u0437 \u043C\u0435\u0442\u0440\u0438\u043A (retention, ARPU, LTV) \u0438 A/B \u0442\u0435\u0441\u0442\u044B. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u0441\u0445\u0435\u043C\u0443 \u0441\u043E\u0431\u044B\u0442\u0438\u0439, \u0434\u0430\u0448\u0431\u043E\u0440\u0434\u044B \u0438 \u043F\u0430\u0439\u043F\u043B\u0430\u0439\u043D \u0434\u0430\u043D\u043D\u044B\u0445 (\u043A\u043B\u0438\u0435\u043D\u0442 \u2192 \u0441\u0435\u0440\u0432\u0435\u0440 \u2192 DWH \u2192 BI). \u0411\u0435\u0437 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0438 \u0438\u0433\u0440\u044B \u0441\u043B\u0435\u043F\u044B: \u043D\u0435\u043B\u044C\u0437\u044F \u043F\u043E\u043D\u044F\u0442\u044C, \u043F\u043E\u0447\u0435\u043C\u0443 \u0438\u0433\u0440\u043E\u043A\u0438 \u0443\u0445\u043E\u0434\u044F\u0442, \u0433\u0434\u0435 \u043E\u043D\u0438 \u0437\u0430\u0441\u0442\u0440\u0435\u0432\u0430\u044E\u0442 \u0438 \u0447\u0442\u043E \u043F\u0440\u0438\u043D\u043E\u0441\u0438\u0442 \u0434\u0435\u043D\u044C\u0433\u0438. \u0412 GameDev \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430 \u2014 \u043D\u0435 \xab\u043F\u043E\u0434\u0434\u0435\u0440\u0436\u043A\u0430\xbb, \u0430 \u0434\u0432\u0438\u0436\u0443\u0449\u0430\u044F \u0441\u0438\u043B\u0430 \u043F\u0440\u043E\u0434\u0443\u043A\u0442\u0430.","permalink":"/sysanalyst-kb.github.io/docs/specialization/gamedev-analytics"},{"id":"integration/kafka","title":"Kafka \u2014 \u0441\u043E\u0431\u044B\u0442\u0438\u0439\u043D\u044B\u0439 streaming","description":"Apache Kafka \u2014 \u044D\u0442\u043E \u0440\u0430\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u0430\u044F \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u0430 \u0434\u043B\u044F \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0438 \u0441\u043E\u0431\u044B\u0442\u0438\u0439\u043D\u044B\u0445 \u043F\u043E\u0442\u043E\u043A\u043E\u0432. \u0412 \u043E\u0442\u043B\u0438\u0447\u0438\u0435 \u043E\u0442 RabbitMQ, Kafka \u043D\u0435 \u0443\u0434\u0430\u043B\u044F\u0435\u0442 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u044F \u043F\u043E\u0441\u043B\u0435 \u043F\u0440\u043E\u0447\u0442\u0435\u043D\u0438\u044F \u2014 \u043E\u043D\u0430 \u0445\u0440\u0430\u043D\u0438\u0442 \u0438\u0445 \u0432 \u043B\u043E\u0433\u0435 \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u043E\u0435 \u0432\u0440\u0435\u043C\u044F (retention).","permalink":"/sysanalyst-kb.github.io/docs/integration/kafka"},{"id":"specialization/gamedev-liveops","title":"LiveOps \u2014 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0436\u0438\u0432\u044B\u043C \u043F\u0440\u043E\u0434\u0443\u043A\u0442\u043E\u043C","description":"LiveOps \u2014 \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E\u0435 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0438\u0433\u0440\u043E\u0439 \u043F\u043E\u0441\u043B\u0435 \u0437\u0430\u043F\u0443\u0441\u043A\u0430: \u0438\u0432\u0435\u043D\u0442\u044B, \u0431\u043E\u0435\u0432\u044B\u0435 \u043F\u0440\u043E\u043F\u0443\u0441\u043A\u0438 (Battle Pass), \u0435\u0436\u0435\u0434\u043D\u0435\u0432\u043D\u044B\u0435 \u0437\u0430\u0434\u0430\u043D\u0438\u044F, \u0441\u0435\u0437\u043E\u043D\u043D\u044B\u0439 \u043A\u043E\u043D\u0442\u0435\u043D\u0442 \u0438 \u0440\u043E\u0442\u0430\u0446\u0438\u044F \u043C\u0430\u0433\u0430\u0437\u0438\u043D\u0430. \u0426\u0435\u043B\u044C \u2014 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044C \u0438\u043D\u0442\u0435\u0440\u0435\u0441 \u0438\u0433\u0440\u043E\u043A\u043E\u0432, \u0443\u0432\u0435\u043B\u0438\u0447\u0438\u0432\u0430\u0442\u044C retention \u0438 \u0434\u043E\u0445\u043E\u0434 \u043D\u0430 \u043F\u0440\u043E\u0442\u044F\u0436\u0435\u043D\u0438\u0438 \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u0438 \u043B\u0435\u0442. \u0425\u043E\u0440\u043E\u0448\u0438\u0439 LiveOps \u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442 \u0438\u0433\u0440\u0443 \u0432 \xab\u0436\u0438\u0432\u043E\u0439 \u0441\u0435\u0440\u0432\u0438\u0441\xbb (Games-as-a-Service), \u0433\u0434\u0435 \u043A\u0430\u0436\u0434\u044B\u0439 \u0434\u0435\u043D\u044C \u0435\u0441\u0442\u044C \u043F\u0440\u0438\u0447\u0438\u043D\u0430 \u0437\u0430\u0439\u0442\u0438. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u043A\u043E\u043D\u0442\u0435\u043D\u0442-\u043A\u0430\u043B\u0435\u043D\u0434\u0430\u0440\u044C, \u0444\u043E\u0440\u043C\u0443\u043B\u044B \u0438\u0432\u0435\u043D\u0442\u043E\u0432, \u043C\u0435\u0442\u0440\u0438\u043A\u0438 \u0438\u0445 \u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u0438 \u0438 \u0441\u0432\u044F\u0437\u044C \u0441 \u044D\u043A\u043E\u043D\u043E\u043C\u0438\u043A\u043E\u0439 \u0438\u0433\u0440\u044B.","permalink":"/sysanalyst-kb.github.io/docs/specialization/gamedev-liveops"}],"unlisted":false}}')}}]);